165	interface IfAXIS128;
166	    wire [127:0]    tdata;
167	    wire [3:0]      tkeepdw;
168	    wire            tvalid;
169	    wire            tlast;
170	    wire [8:0]      tuser;      // [0] = first
171	                                // [1] = last
172	                                // [8:2] = BAR, 2=BAR0, 3=BAR1, .. 7=BAR5, 8=EXPROM
173	    
174	    wire            tready;
175	    wire            has_data;
176	    
177	    modport source(
178	        input  tready,
179	        output tdata, tkeepdw, tvalid, tlast, tuser, has_data
180	    );
181	    
182	    modport sink(
183	        output tready,
184	        input  tdata, tkeepdw, tvalid, tlast, tuser, has_data
185	    );
186	    
